diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..a40162ad4684 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8268,6 +8268,7 @@ static std::optional<bool> isImpliedCondCommonOperandWithConstants(
 /// Return true if LHS implies RHS (expanded to its components as "R0 RPred R1")
 /// is true.  Return false if LHS implies RHS is false. Otherwise, return
 /// std::nullopt if we can't infer anything.
+
 static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
                                               CmpInst::Predicate RPred,
                                               const Value *R0, const Value *R1,
@@ -8292,12 +8293,48 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   if (L0 == R0 && match(L1, m_APInt(LC)) && match(R1, m_APInt(RC)))
     return isImpliedCondCommonOperandWithConstants(LPred, *LC, RPred, *RC);

+  // Handle the case where both comparisons are ULT and one operand is an add
+  // of the other two operands.
+  // For unsigned addition: (a + b) < a  implies (a + b) < b, and vice versa.
+  if (LPred == CmpInst::ICMP_ULT && RPred == CmpInst::ICMP_ULT) {
+    // Check all four possible operand arrangements where the sum appears
+    // in both comparisons.
+    auto CheckImplication = [&](const Value *Sum, const Value *A, const Value *B) -> std::optional<bool> {
+      // Check if Sum is A + B (commutative)
+      if (match(Sum, m_c_Add(m_Specific(A), m_Specific(B))))
+        return true;
+      return std::nullopt;
+    };
+
+    // Case 1: L0 == R0 (sum is first operand in both)
+    if (L0 == R0) {
+      if (auto Result = CheckImplication(L0, L1, R1))
+        return Result;
+    }
+    // Case 2: L1 == R1 (sum is second operand in both)
+    if (L1 == R1) {
+      if (auto Result = CheckImplication(L1, L0, R0))
+        return Result;
+    }
+    // Case 3: L0 == R1 (sum is first in LHS, second in RHS)
+    if (L0 == R1) {
+      if (auto Result = CheckImplication(L0, L1, R0))
+        return Result;
+    }
+    // Case 4: L1 == R0 (sum is second in LHS, first in RHS)
+    if (L1 == R0) {
+      if (auto Result = CheckImplication(L1, L0, R1))
+        return Result;
+    }
+  }
+
   if (LPred == RPred)
     return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);

   return std::nullopt;
 }

+
 /// Return true if LHS implies RHS is true.  Return false if LHS implies RHS is
 /// false.  Otherwise, return std::nullopt if we can't infer anything.  We
 /// expect the RHS to be an icmp and the LHS to be an 'and', 'or', or a 'select'
